package com.company.supervision.application.messaging;import com.company.supervision.application.organization.WecomIntegrationService;import com.company.supervision.domain.model.messaging.WecomWebhook;import com.company.supervision.infrastructure.repository.messaging.WecomWebhookMapper;import com.company.supervision.infrastructure.security.SecretCipher;import com.fasterxml.jackson.databind.JsonNode;import org.springframework.core.io.ByteArrayResource;import org.springframework.http.*;import org.springframework.stereotype.Service;import org.springframework.util.*;import org.springframework.web.client.RestTemplate;import org.springframework.web.multipart.MultipartFile;import java.util.*;@Service public class WecomMediaService{private final RestTemplate http;private final WecomWebhookMapper hooks;private final SecretCipher cipher;private final WecomIntegrationService wecom;public WecomMediaService(RestTemplate h,WecomWebhookMapper m,SecretCipher c,WecomIntegrationService w){http=h;hooks=m;cipher=c;wecom=w;}public Map<String,Object>upload(MultipartFile file,String type,String channel,Long webhookId)throws Exception{if(!Set.of("file","voice","image").contains(type))throw new IllegalArgumentException("Unsupported media type");String url;if("GROUP_WEBHOOK".equals(channel)){WecomWebhook h=hooks.selectById(webhookId);String webhook=cipher.decrypt(h.getWebhookCipher());String key=webhook.substring(webhook.indexOf("key=")+4);url="https://qyapi.weixin.qq.com/cgi-bin/webhook/upload_media?key="+key+"&type="+type;}else url="https://qyapi.weixin.qq.com/cgi-bin/media/upload?access_token="+wecom.token(false)+"&type="+type;MultiValueMap<String,Object>b=new LinkedMultiValueMap<>();b.add("media",new ByteArrayResource(file.getBytes()){public String getFilename(){return file.getOriginalFilename();}});HttpHeaders h=new HttpHeaders();h.setContentType(MediaType.MULTIPART_FORM_DATA);JsonNode r=http.postForObject(url,new HttpEntity<>(b,h),JsonNode.class);if(r==null||r.path("errcode").asInt()!=0)throw new IllegalStateException("Media upload failed");return Map.of("mediaId",r.path("media_id").asText(),"expiresInSeconds",259200);}}